cd /tmp/sv-73c1cc3745574a8e8b216fd73093b39b/simple-solution && dotnet list package --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
def pkgs(data):
    d = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                d[(name, pkg['id'])] = pkg['resolvedVersion']
    return d
bp, ap = pkgs(b), pkgs(a)
if bp == ap:
    print('All packages match baseline — conversion is version-neutral.')
else:
    for k in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv, av = bp.get(k, 'MISSING'), ap.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]}/{k[1]}: {bv} -> {av}')
"

